// Strip markdown fences before parsing - Claude wraps JSON in
// ```json fences by default despite the explicit instruction
// not to. Same pattern used across P01-P10 and M01-M04.

const rawText = $input.first().json.content[0].text;
const stripped = rawText.replace(/```json\s*|```/g, '').trim();

let brief;
try {
  brief = JSON.parse(stripped);
} catch (e) {
  throw new Error(`Failed to parse SEO brief JSON: ${e.message}. Raw text: ${stripped.substring(0, 300)}`);
}

return [
  {
    json: {
      ...brief,
      competitor_data: $('Simulated Competitor Research [MOCK]').first().json.competitor_data
    }
  }
];

