const rawText = $input.first().json.content[0].text;
const stripped = rawText.replace(/```json\s*|```/g, '').trim();

let review;
try {
  review = JSON.parse(stripped);
} catch (e) {
  throw new Error(`Failed to parse self-review JSON: ${e.message}. Raw text: ${stripped.substring(0, 300)}`);
}

return [
  {
    json: {
      ...review,
      draft: $('Parse Article Draft').first().json,
      revision_count: ($('Parse Article Draft').first().json.revision_count || 0)
    }
  }
];

// AGENT LOOP GUARD: cap revisions at 2 attempts to prevent
// thrashing - see Agentic AI Fundamentals Q12. If review still
// fails after 2 revisions, route to human review instead of
// looping indefinitely.

const current = $json.draft.revision_count || 0;

if (current >= 2) {
  return [{
    json: {
      ...$json,
      revision_count: current,
      escalate_to_human: true
    }
  }];
}

return [{
  json: {
    ...$json,
    revision_count: current + 1,
    escalate_to_human: false
  }
}];

