const rawText = $input.first().json.content[0].text;
const stripped = rawText.replace(/```json\s*|```/g, '').trim();

let revised;
try {
  revised = JSON.parse(stripped);
} catch (e) {
  throw new Error(`Failed to parse revised draft JSON: ${e.message}. Raw text: ${stripped.substring(0, 300)}`);
}

const priorRevisionCount = $('Check Revision Count').first().json.revision_count;

return [
  {
    json: {
      ...revised,
      brief: $('Check Revision Count').first().json.draft.brief,
      revision_count: priorRevisionCount
    }
  }
];

// Final payload shaped for WordPress REST API.
// SWAP POINT for live posting - see WordPress node below.

const article = $json.draft || $json;

return [{
  json: {
    title: article.article_title,
    content: article.article_body_markdown,
    excerpt: article.meta_description,
    status: "draft",
    meta: {
      meta_description: article.meta_description
    },
    pipeline_status: $('Max Revisions Hit?').isExecuted
      ? "published_after_max_revisions_human_flagged"
      : "published_after_passing_review"
  }
}];

// Logging step - same dual-visibility pattern as M03
// (Invoice Tracker): one row per run, status visible at a glance.

const payload = $('Prepare WordPress Payload').first().json;

return [{
  json: {
    run_timestamp: new Date().toISOString(),
    target_keyword: $('Set Target Keyword').first().json.target_keyword,
    article_title: payload.title,
    word_count: payload.content ? payload.content.split(/\s+/).length : null,
    pipeline_status: payload.pipeline_status,
    wordpress_status: "draft (unvalidated - see node notes)"
  }
}];
